<span class="line"><span style="color:#66D9EF;font-style:italic;">def</span><span style="color:#A6E22E;"> detail</span><span style="color:#F8F8F2;">(</span><span style="color:#FD971F;font-style:italic;">request</span><span style="color:#F8F8F2;">, </span><span style="color:#FD971F;font-style:italic;">pk</span><span style="color:#F8F8F2;">):</span></span>
